sql:
SELECT ethnicity_type, AVG(population_percentage) AS average_population_percentage
FROM ethnicities
GROUP BY ethnicity_type;

SELECT AVG(population_percentage) AS average_population_percentage
FROM ethnicities
WHERE ethnicity_type = 'ONS 2011 5 + 1';

SELECT COUNT(*) AS total_entries, AVG(average_income) AS average_income
FROM household_incomes
WHERE income_id = 0;

SELECT income_range, average_income
FROM household_incomes
WHERE income_id != 0;

SELECT measure_description
FROM crime_measures
WHERE methodology = 'Household survey';

SELECT COUNT(*) AS count_of_annual_measures
FROM crime_measures
WHERE frequency = 'Annual';
